    50→export class ExtensionHostProcess {
    51→
    52→	private readonly _id: string;
    53→
    54→	public get onStdout(): Event<string> {
    55→		return this._extensionHostStarter.onDynamicStdout(this._id);
    56→	}
    57→
    58→	public get onStderr(): Event<string> {
    59→		return this._extensionHostStarter.onDynamicStderr(this._id);
    60→	}
    61→
    62→	public get onMessage(): Event<any> {
    63→		return this._extensionHostStarter.onDynamicMessage(this._id);
    64→	}
    65→
    66→	public get onExit(): Event<{ code: number; signal: string }> {
    67→		return this._extensionHostStarter.onDynamicExit(this._id);
    68→	}
    69→
    70→	constructor(
    71→		id: string,
    72→		private readonly _extensionHostStarter: IExtensionHostStarter,
    73→	) {
    74→		this._id = id;
    75→	}
    76→
    77→	public start(opts: IExtensionHostProcessOptions): Promise<{ pid: number | undefined }> {
    78→		return this._extensionHostStarter.start(this._id, opts);
    79→	}
    80→
    81→	public enableInspectPort(): Promise<boolean> {
    82→		return this._extensionHostStarter.enableInspectPort(this._id);
    83→	}
    84→
    85→	public kill(): Promise<void> {
    86→		return this._extensionHostStarter.kill(this._id);
