  1471→	private static _TIME_LIMIT = 5 * 60 * 1000; // 5 minutes
  1472→	private static _CRASH_LIMIT = 3;
  1473→
  1474→	private readonly _recentCrashes: IExtensionHostCrashInfo[] = [];
  1475→
  1476→	private _removeOldCrashes(): void {
  1477→		const limit = Date.now() - ExtensionHostCrashTracker._TIME_LIMIT;
  1478→		while (this._recentCrashes.length > 0 && this._recentCrashes[0].timestamp < limit) {
  1479→			this._recentCrashes.shift();
  1480→		}
  1481→	}
  1482→
  1483→	public registerCrash(): void {
  1484→		this._removeOldCrashes();
  1485→		this._recentCrashes.push({ timestamp: Date.now() });
  1486→	}
  1487→
  1488→	public shouldAutomaticallyRestart(): boolean {
  1489→		this._removeOldCrashes();
  1490→		return (this._recentCrashes.length < ExtensionHostCrashTracker._CRASH_LIMIT);
  1491→	}
  1492→}
