   276→		// Remove any environment variables that are not allowed
   277→		removeDangerousEnvVariables(env);
   278→
   279→		// Ensure all values are strings, otherwise the process will not start
   280→		for (const key of Object.keys(env)) {
   281→			env[key] = String(env[key]);
   282→		}
   283→
   284→		return env;
   285→	}
   286→
   287→	private registerListeners(process: ElectronUtilityProcess, configuration: IUtilityProcessConfiguration, serviceName: string): void {
   288→
   289→		// Stdout
   290→		if (process.stdout) {
   291→			const stdoutDecoder = new StringDecoder('utf-8');
   292→			this._register(Event.fromNodeEventEmitter<string | Buffer>(process.stdout, 'data')(chunk => this._onStdout.fire(typeof chunk === 'string' ? chunk : stdoutDecoder.write(chunk))));
   293→		}
   294→
   295→		// Stderr
   296→		if (process.stderr) {
   297→			const stderrDecoder = new StringDecoder('utf-8');
   298→			this._register(Event.fromNodeEventEmitter<string | Buffer>(process.stderr, 'data')(chunk => this._onStderr.fire(typeof chunk === 'string' ? chunk : stderrDecoder.write(chunk))));
   299→		}
   300→
   301→		// Messages
   302→		this._register(Event.fromNodeEventEmitter(process, 'message')(msg => this._onMessage.fire(msg)));
   303→
   304→		// Spawn
   305→		this._register(Event.fromNodeEventEmitter<void>(process, 'spawn')(() => {
   306→			this.processPid = process.pid;
   307→
   308→			if (typeof process.pid === 'number') {
   309→				UtilityProcess.all.set(process.pid, { pid: process.pid, name: isWindowUtilityProcessConfiguration(configuration) ? `${configuration.type} [${configuration.responseWindowId}]` : configuration.type });
   310→			}
   311→
   312→			this.log('successfully created', Severity.Info);
   313→			this._onSpawn.fire(process.pid);
   314→		}));
   315→
   316→		// Exit
   317→		this._register(Event.fromNodeEventEmitter<number>(process, 'exit')(code => {
   318→			this.log(`received exit event with code ${code}`, Severity.Info);
   319→
   320→			// Event
   321→			this._onExit.fire({ pid: this.processPid!, code, signal: 'unknown' });
   322→
   323→			// Cleanup
   324→			this.onDidExitOrCrashOrKill();
   325→		}));
   326→
   327→		// V8 Error
   328→		this._register(Event.fromNodeEventEmitter(process, 'error', (type, location, report) => ({ type, location, report }))(({ type, location, report }) => {
   329→			this.log(`crashed due to ${type} from V8 at ${location}`, Severity.Info);
   330→
   331→			let addons: string[] = [];
   332→			try {
   333→				const reportJSON = JSON.parse(report);
   334→				addons = reportJSON.sharedObjects
   335→					.filter((sharedObject: string) => sharedObject.endsWith('.node'))
   336→					.map((addon: string) => {
   337→						const index = addon.indexOf('extensions') === -1 ? addon.indexOf('node_modules') : addon.indexOf('extensions');
   338→						return addon.substring(index);
   339→					});
   340→			} catch (e) {
   341→				// ignore
   342→			}
   343→
   344→			// Telemetry
   345→			type UtilityProcessV8ErrorClassification = {
   346→				processtype: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The type of utility process to understand the origin of the crash better.' };
   347→				error: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The type of error from the utility process to understand the nature of the crash better.' };
   348→				location: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The source location that triggered the crash to understand the nature of the crash better.' };
   349→				addons: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The list of addons loaded in the utility process to understand the nature of the crash better' };
   350→				owner: 'deepak1556';
   351→				comment: 'Provides insight into V8 sandbox FATAL error caused by native addons.';
   352→			};
   353→			type UtilityProcessV8ErrorEvent = {
   354→				processtype: string;
   355→				error: string;
   356→				location: string;
   357→				addons: string[];
   358→			};
   359→			this.telemetryService.publicLog2<UtilityProcessV8ErrorEvent, UtilityProcessV8ErrorClassification>('utilityprocessv8error', {
   360→				processtype: configuration.type,
   361→				error: type,
   362→				location,
   363→				addons
   364→			});
   365→		}));
   366→
   367→		// Child process gone
   368→		this._register(Event.fromNodeEventEmitter<{ details: Details }>(app, 'child-process-gone', (event, details) => ({ event, details }))(({ details }) => {
   369→			if (details.type === 'Utility' && details.name === serviceName) {
   370→				this.log(`crashed with code ${details.exitCode} and reason '${details.reason}'`, Severity.Error);
   371→
   372→				// Telemetry
   373→				type UtilityProcessCrashClassification = {
   374→					type: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The type of utility process to understand the origin of the crash better.' };
   375→					reason: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The reason of the utility process crash to understand the nature of the crash better.' };
   376→					code: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The exit code of the utility process to understand the nature of the crash better' };
   377→					owner: 'bpasero';
   378→					comment: 'Provides insight into reasons the utility process crashed.';
   379→				};
   380→				type UtilityProcessCrashEvent = {
   381→					type: string;
   382→					reason: string;
   383→					code: number;
   384→				};
   385→				this.telemetryService.publicLog2<UtilityProcessCrashEvent, UtilityProcessCrashClassification>('utilityprocesscrash', {
   386→					type: configuration.type,
   387→					reason: details.reason,
   388→					code: details.exitCode
   389→				});
   390→
   391→				// Event
   392→				this._onCrash.fire({ pid: this.processPid!, code: details.exitCode, reason: details.reason });
   393→
   394→				// Cleanup
   395→				this.onDidExitOrCrashOrKill();
   396→			}
   397→		}));
   398→	}
   399→
   400→	once(message: unknown, callback: () => void): void {
   401→		const disposable = this._register(this._onMessage.event(msg => {
   402→			if (msg === message) {
   403→				disposable.dispose();
   404→
   405→				callback();
   406→			}
   407→		}));
   408→	}
   409→
   410→	postMessage(message: unknown, transfer?: Electron.MessagePortMain[]): boolean {
   411→		if (!this.process) {
   412→			return false; // already killed, crashed or never started
   413→		}
   414→
   415→		this.process.postMessage(message, transfer);
   416→
   417→		return true;
   418→	}
   419→
   420→	connect(payload?: unknown): Electron.MessagePortMain {
   421→		const { port1: outPort, port2: utilityProcessPort } = new MessageChannelMain();
   422→		this.postMessage(payload, [utilityProcessPort]);
   423→
   424→		return outPort;
   425→	}
   426→
   427→	enableInspectPort(): boolean {
   428→		if (!this.process || typeof this.processPid !== 'number') {
   429→			return false;
   430→		}
   431→
   432→		this.log('enabling inspect port', Severity.Info);
   433→
   434→		interface ProcessExt {
   435→			_debugProcess?(pid: number): unknown;
   436→		}
   437→
   438→		// use (undocumented) _debugProcess feature of node if available
   439→		const processExt = <ProcessExt>process;
   440→		if (typeof processExt._debugProcess === 'function') {
   441→			processExt._debugProcess(this.processPid);
   442→
   443→			return true;
   444→		}
   445→
   446→		// not supported...
   447→		return false;
   448→	}
